     5→//! Tests for jjx_garland command
     6→//!
     7→//! Tests the garland operation which celebrates heat completion and creates
     8→//! a continuation heat.
     9→
    10→use super::jjrg_gallops::*;
    11→use super::jjro_ops::jjrg_garland;
    12→use super::jjrt_types::{jjrg_PaceState, jjrg_HeatStatus, jjrg_Tack, jjrg_Pace, jjrg_Heat, jjrg_Gallops, jjrg_GarlandArgs, JJRG_UNKNOWN_COMMIT};
    13→use super::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
    14→use std::collections::BTreeMap;
    15→use indexmap::IndexMap;
    16→
    17→// Helper to create a minimal valid Gallops structure
    18→fn make_valid_gallops() -> jjrg_Gallops {
    19→    jjrg_Gallops {
    20→        next_heat_seed: "AB".to_string(),
    21→        heats: IndexMap::new(),
    22→    }
    23→}
    24→
    25→// Helper to create a valid Tack
    26→fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
    27→    jjrg_Tack {
    28→        ts: "260101-1200".to_string(),
    29→        state,
    30→        text: "Test tack text".to_string(),
    31→        silks: silks.to_string(),
    32→        commit: JJRG_UNKNOWN_COMMIT.to_string(),
    33→        direction,
    34→    }
    35→}
    36→
    37→// Helper to create a valid Heat with multiple paces
    38→fn make_heat_with_paces(heat_id: &str, silks: &str, pace_states: Vec<jjrg_PaceState>) -> (String, jjrg_Heat) {
    39→    let heat_key = format!("₣{}", heat_id);
    40→    let mut paces = BTreeMap::new();
    41→    let mut order = Vec::new();
    42→
    43→    for (idx, state) in pace_states.iter().enumerate() {
    44→        let pace_key = format!("₢{}AA{}", heat_id, char::from(b'A' + idx as u8));
    45→        let pace_silks = format!("pace-{}", idx);
    46→        let pace = jjrg_Pace {
    47→            tacks: vec![make_valid_tack(state.clone(), &pace_silks, None)],
    48→        };
    49→        paces.insert(pace_key.clone(), pace);
    50→        order.push(pace_key);
    51→    }
    52→
    53→    // Calculate next seed
    54→    let next_char = char::from(b'A' + pace_states.len() as u8);
    55→    let next_pace_seed = format!("AA{}", next_char);
    56→
    57→    let heat = jjrg_Heat {
    58→        silks: silks.to_string(),
    59→        creation_time: "260101".to_string(),
    60→        status: jjrg_HeatStatus::Racing,
    61→        order,
    62→        next_pace_seed,
    63→        paddock_file: format!(".claude/jjm/jjp_{}.md", heat_id),
    64→        paces,
    65→    };
    66→    (heat_key, heat)
    67→}
    68→
    69→#[test]
    70→fn jjtgl_garland_heat_not_found() {
    71→    let mut gallops = make_valid_gallops();
    72→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_not_found");
    73→    let _ = std::fs::remove_dir_all(&temp_dir);
    74→    std::fs::create_dir_all(&temp_dir).unwrap();
    75→
    76→    let args = jjrg_GarlandArgs {
    77→        firemark: "CD".to_string(),
    78→    };
    79→
    80→    let result = jjrg_garland(&mut gallops, args, &temp_dir);
    81→    assert!(result.is_err());
    82→    assert!(result.unwrap_err().contains("not found"));
    83→
    84→    let _ = std::fs::remove_dir_all(&temp_dir);
    85→}
    86→
    87→#[test]
    88→fn jjtgl_garland_no_actionable_paces() {
    89→    let mut gallops = make_valid_gallops();
    90→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_no_actionable");
    91→    let _ = std::fs::remove_dir_all(&temp_dir);
    92→    std::fs::create_dir_all(&temp_dir).unwrap();
    93→
    94→    // Create heat with only complete and abandoned paces
    95→    let (heat_key, heat) = make_heat_with_paces(
    96→        "AB",
    97→        "test-heat",
    98→        vec![jjrg_PaceState::Complete, jjrg_PaceState::Abandoned],
    99→    );
   100→
   101→    // Create paddock file
   102→    let paddock_path = temp_dir.join(&heat.paddock_file);
   103→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   104→    std::fs::write(&paddock_path, "Test paddock content").unwrap();
   105→
   106→    gallops.heats.insert(heat_key.clone(), heat);
   107→
   108→    let args = jjrg_GarlandArgs {
   109→        firemark: "AB".to_string(),
   110→    };
   111→
   112→    let result = jjrg_garland(&mut gallops, args, &temp_dir);
   113→    assert!(result.is_err());
   114→    assert!(result.unwrap_err().contains("no actionable paces"));
   115→
   116→    let _ = std::fs::remove_dir_all(&temp_dir);
   117→}
   118→
   119→#[test]
   120→fn jjtgl_garland_successful_with_rough_paces() {
   121→    let mut gallops = make_valid_gallops();
   122→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_success_rough");
   123→    let _ = std::fs::remove_dir_all(&temp_dir);
   124→    std::fs::create_dir_all(&temp_dir).unwrap();
   125→
   126→    // Create heat with mixed paces: 2 complete, 2 rough
   127→    let (heat_key, heat) = make_heat_with_paces(
   128→        "AB",
   129→        "test-heat",
   130→        vec![
   131→            jjrg_PaceState::Complete,
   132→            jjrg_PaceState::Complete,
   133→            jjrg_PaceState::Rough,
   134→            jjrg_PaceState::Rough,
   135→        ],
   136→    );
   137→
   138→    // Create paddock file
   139→    let paddock_path = temp_dir.join(&heat.paddock_file);
   140→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   141→    std::fs::write(&paddock_path, "Original paddock content\n\nMore details here.").unwrap();
   142→
   143→    gallops.heats.insert(heat_key.clone(), heat);
   144→
   145→    let args = jjrg_GarlandArgs {
   146→        firemark: "AB".to_string(),
   147→    };
   148→
   149→    let result = jjrg_garland(&mut gallops, args, &temp_dir).unwrap();
   150→
   151→    // Verify result structure
   152→    assert_eq!(result.old_firemark, "₣AB");
   153→    assert_eq!(result.old_silks, "garlanded-test-heat-01");
   154→    assert!(result.new_firemark.starts_with('₣'));
   155→    assert_eq!(result.new_silks, "test-heat-02");
   156→    assert_eq!(result.paces_transferred, 2);
   157→    assert_eq!(result.paces_retained, 2);
   158→
   159→    // Verify old heat was updated
   160→    let old_heat = gallops.heats.get(&result.old_firemark).unwrap();
   161→    assert_eq!(old_heat.silks, "garlanded-test-heat-01");
   162→    assert_eq!(old_heat.status, jjrg_HeatStatus::Stabled);
   163→    assert_eq!(old_heat.paces.len(), 2); // Only retained paces
   164→
   165→    // Verify new heat was created
   166→    let new_heat = gallops.heats.get(&result.new_firemark).unwrap();
   167→    assert_eq!(new_heat.silks, "test-heat-02");
   168→    assert_eq!(new_heat.status, jjrg_HeatStatus::Racing);
   169→    assert_eq!(new_heat.paces.len(), 2); // Only transferred paces
   170→
   171→    // Verify new heat is at front of heats map
   172→    let first_key = gallops.heats.keys().next().unwrap();
   173→    assert_eq!(first_key, &result.new_firemark);
   174→
   175→    // Verify paddock marker was added to old heat
   176→    let old_paddock_content = std::fs::read_to_string(temp_dir.join(&old_heat.paddock_file)).unwrap();
   177→    assert!(old_paddock_content.contains("Garlanded at pace 2"));
   178→
   179→    // Verify paddock content was copied to new heat (without marker)
   180→    let new_paddock_content = std::fs::read_to_string(temp_dir.join(&new_heat.paddock_file)).unwrap();
   181→    assert!(new_paddock_content.contains("Original paddock content"));
   182→    assert!(!new_paddock_content.contains("Garlanded at pace"));
   183→
   184→    let _ = std::fs::remove_dir_all(&temp_dir);
   185→}
