   187→#[test]
   188→fn jjtgl_garland_successful_with_bridled_paces() {
   189→    let mut gallops = make_valid_gallops();
   190→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_success_bridled");
   191→    let _ = std::fs::remove_dir_all(&temp_dir);
   192→    std::fs::create_dir_all(&temp_dir).unwrap();
   193→
   194→    // Create heat with complete and bridled paces
   195→    let heat_key = "₣AB".to_string();
   196→    let mut paces = BTreeMap::new();
   197→    let mut order = Vec::new();
   198→
   199→    // Complete pace
   200→    let pace1_key = "₢ABAAA".to_string();
   201→    paces.insert(pace1_key.clone(), jjrg_Pace {
   202→        tacks: vec![make_valid_tack(jjrg_PaceState::Complete, "pace-0", None)],
   203→    });
   204→    order.push(pace1_key.clone());
   205→
   206→    // Bridled pace (should be transferred)
   207→    let pace2_key = "₢ABAAB".to_string();
   208→    paces.insert(pace2_key.clone(), jjrg_Pace {
   209→        tacks: vec![make_valid_tack(
   210→            jjrg_PaceState::Bridled,
   211→            "pace-1",
   212→            Some("Execute autonomously".to_string()),
   213→        )],
   214→    });
   215→    order.push(pace2_key.clone());
   216→
   217→    let heat = jjrg_Heat {
   218→        silks: "test-heat".to_string(),
   219→        creation_time: "260101".to_string(),
   220→        status: jjrg_HeatStatus::Racing,
   221→        order,
   222→        next_pace_seed: "AAC".to_string(),
   223→        paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
   224→        paces,
   225→    };
   226→
   227→    // Create paddock file
   228→    let paddock_path = temp_dir.join(&heat.paddock_file);
   229→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   230→    std::fs::write(&paddock_path, "Paddock content").unwrap();
   231→
   232→    gallops.heats.insert(heat_key.clone(), heat);
   233→
   234→    let args = jjrg_GarlandArgs {
   235→        firemark: "AB".to_string(),
   236→    };
   237→
   238→    let result = jjrg_garland(&mut gallops, args, &temp_dir).unwrap();
   239→
   240→    // Verify bridled pace was transferred
   241→    assert_eq!(result.paces_transferred, 1);
   242→    assert_eq!(result.paces_retained, 1);
   243→
   244→    // Verify new heat has the bridled pace
   245→    let new_heat = gallops.heats.get(&result.new_firemark).unwrap();
   246→    assert_eq!(new_heat.paces.len(), 1);
   247→    let new_pace = new_heat.paces.values().next().unwrap();
   248→    assert_eq!(new_pace.tacks[0].state, jjrg_PaceState::Bridled);
   249→    assert!(new_pace.tacks[0].direction.is_some());
   250→
   251→    let _ = std::fs::remove_dir_all(&temp_dir);
   252→}
