   254→#[test]
   255→fn jjtgl_garland_silks_sequence_parsing_plain() {
   256→    // Test that plain silks get sequence 1
   257→    let (base, seq) = jjrq_parse_silks_sequence("foo-bar");
   258→    assert_eq!(base, "foo-bar");
   259→    assert_eq!(seq, None);
   260→
   261→    let garlanded = jjrq_build_garlanded_silks(&base, seq.unwrap_or(1));
   262→    assert_eq!(garlanded, "garlanded-foo-bar-01");
   263→
   264→    let continuation = jjrq_build_continuation_silks(&base, seq.unwrap_or(1) + 1);
   265→    assert_eq!(continuation, "foo-bar-02");
   266→}
   267→
   268→#[test]
   269→fn jjtgl_garland_silks_sequence_parsing_numbered() {
   270→    // Test that silks with sequence get incremented
   271→    let (base, seq) = jjrq_parse_silks_sequence("foo-bar-03");
   272→    assert_eq!(base, "foo-bar");
   273→    assert_eq!(seq, Some(3));
   274→
   275→    let garlanded = jjrq_build_garlanded_silks(&base, seq.unwrap());
   276→    assert_eq!(garlanded, "garlanded-foo-bar-03");
   277→
   278→    let continuation = jjrq_build_continuation_silks(&base, seq.unwrap() + 1);
   279→    assert_eq!(continuation, "foo-bar-04");
   280→}
