   282→#[test]
   283→fn jjtgl_garland_preserves_pace_order() {
   284→    let mut gallops = make_valid_gallops();
   285→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_order");
   286→    let _ = std::fs::remove_dir_all(&temp_dir);
   287→    std::fs::create_dir_all(&temp_dir).unwrap();
   288→
   289→    // Create heat with specific order: complete, rough, rough, complete
   290→    let (heat_key, heat) = make_heat_with_paces(
   291→        "AB",
   292→        "test-heat",
   293→        vec![
   294→            jjrg_PaceState::Complete,
   295→            jjrg_PaceState::Rough,
   296→            jjrg_PaceState::Rough,
   297→            jjrg_PaceState::Complete,
   298→        ],
   299→    );
   300→
   301→    // Create paddock file
   302→    let paddock_path = temp_dir.join(&heat.paddock_file);
   303→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   304→    std::fs::write(&paddock_path, "Paddock").unwrap();
   305→
   306→    gallops.heats.insert(heat_key.clone(), heat);
   307→
   308→    let args = jjrg_GarlandArgs {
   309→        firemark: "AB".to_string(),
   310→    };
   311→
   312→    let result = jjrg_garland(&mut gallops, args, &temp_dir).unwrap();
   313→
   314→    // Verify new heat has rough paces in original order
   315→    let new_heat = gallops.heats.get(&result.new_firemark).unwrap();
   316→    assert_eq!(new_heat.order.len(), 2);
   317→
   318→    // The two rough paces should maintain their relative order
   319→    // (they were at positions 1 and 2 in original order)
   320→    let new_pace_0 = new_heat.paces.get(&new_heat.order[0]).unwrap();
   321→    let new_pace_1 = new_heat.paces.get(&new_heat.order[1]).unwrap();
   322→    assert_eq!(new_pace_0.tacks[0].silks, "pace-1"); // From original position 1
   323→    assert_eq!(new_pace_1.tacks[0].silks, "pace-2"); // From original position 2
   324→
   325→    let _ = std::fs::remove_dir_all(&temp_dir);
   326→}
