   328→#[test]
   329→fn jjtgl_garland_all_actionable_paces() {
   330→    let mut gallops = make_valid_gallops();
   331→    let temp_dir = std::env::temp_dir().join("jjk_test_garland_all_actionable");
   332→    let _ = std::fs::remove_dir_all(&temp_dir);
   333→    std::fs::create_dir_all(&temp_dir).unwrap();
   334→
   335→    // Create heat with only rough paces
   336→    let (heat_key, heat) = make_heat_with_paces(
   337→        "AB",
   338→        "test-heat",
   339→        vec![jjrg_PaceState::Rough, jjrg_PaceState::Rough, jjrg_PaceState::Rough],
   340→    );
   341→
   342→    // Create paddock file
   343→    let paddock_path = temp_dir.join(&heat.paddock_file);
   344→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   345→    std::fs::write(&paddock_path, "Paddock").unwrap();
   346→
   347→    gallops.heats.insert(heat_key.clone(), heat);
   348→
   349→    let args = jjrg_GarlandArgs {
   350→        firemark: "AB".to_string(),
   351→    };
   352→
   353→    let result = jjrg_garland(&mut gallops, args, &temp_dir).unwrap();
   354→
   355→    // All paces transferred
   356→    assert_eq!(result.paces_transferred, 3);
   357→    assert_eq!(result.paces_retained, 0);
   358→
   359→    // Old heat should be empty
   360→    let old_heat = gallops.heats.get(&result.old_firemark).unwrap();
   361→    assert_eq!(old_heat.paces.len(), 0);
   362→    assert_eq!(old_heat.order.len(), 0);
   363→
   364→    // New heat should have all paces
   365→    let new_heat = gallops.heats.get(&result.new_firemark).unwrap();
   366→    assert_eq!(new_heat.paces.len(), 3);
   367→
   368→    let _ = std::fs::remove_dir_all(&temp_dir);
