    40→/// Run the muster command - list Heats as TSV
    41→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    42→    let gallops = match Gallops::jjrg_load(&args.file) {
    43→        Ok(g) => g,
    44→        Err(e) => {
    45→            eprintln!("jjx_muster: error: {}", e);
    46→            return 1;
    47→        }
    48→    };
    49→
    50→    // Collect heats with status info for sorting
    51→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    52→
    53→    // Apply status filter if specified
    54→    if let Some(ref filter_status) = args.status {
    55→        let filter_lowercase = filter_status.to_lowercase();
    56→        heats_by_status.retain(|(_, heat)| {
    57→            let heat_status_str = match heat.status {
    58→                HeatStatus::Racing => "racing",
    59→                HeatStatus::Stabled => "stabled",
    60→                HeatStatus::Retired => "retired",
    61→            };
    62→            heat_status_str == filter_lowercase
    63→        });
    64→    }
    65→
    66→    // Sort: racing first, then stabled, then retired
    67→    heats_by_status.sort_by(|a, b| {
    68→        let a_status_order = match a.1.status {
    69→            HeatStatus::Racing => 0,
    70→            HeatStatus::Stabled => 1,
    71→            HeatStatus::Retired => 2,
    72→        };
    73→        let b_status_order = match b.1.status {
    74→            HeatStatus::Racing => 0,
    75→            HeatStatus::Stabled => 1,
    76→            HeatStatus::Retired => 2,
    77→        };
    78→        a_status_order.cmp(&b_status_order)
    79→    });
    80→
    81→    // Set up table with column definitions
    82→    let mut table = jjrp_Table::jjrp_new(vec![
    83→        jjrp_Column::new("₣Fire", jjrp_Align::Left),
    84→        jjrp_Column::new("Silks", jjrp_Align::Left),
    85→        jjrp_Column::new("Status", jjrp_Align::Left),
    86→        jjrp_Column::new("Done", jjrp_Align::Right),
    87→        jjrp_Column::new("Total", jjrp_Align::Right),
    88→    ]);
    89→
    90→    // Measure all rows to compute column widths
    91→    for (key, heat) in &heats_by_status {
    92→        // Count paces where state != Abandoned
    93→        let defined_count = heat.paces.values().filter(|pace| {
    94→            if let Some(tack) = pace.tacks.first() {
    95→                tack.state != PaceState::Abandoned
    96→            } else {
    97→                true
    98→            }
    99→        }).count();
   100→
   101→        // Count paces where state == Complete
   102→        let completed_count = heat.paces.values().filter(|pace| {
   103→            if let Some(tack) = pace.tacks.first() {
   104→                tack.state == PaceState::Complete
   105→            } else {
   106→                false
   107→            }
   108→        }).count();
   109→
   110→        let status_str = match heat.status {
   111→            HeatStatus::Racing => "racing",
   112→            HeatStatus::Stabled => "stabled",
   113→            HeatStatus::Retired => "retired",
   114→        };
   115→
   116→        table.jjrp_measure(&[
   117→            key,
   118→            &heat.silks,
   119→            status_str,
   120→            &completed_count.to_string(),
   121→            &defined_count.to_string(),
   122→        ]);
   123→    }
   124→
   125→    // Print header and separator
   126→    table.jjrp_print_header();
   127→    table.jjrp_print_separator();
   128→
   129→    // Print data rows
   130→    for (key, heat) in heats_by_status {
   131→        // Count paces where state != Abandoned
   132→        let defined_count = heat.paces.values().filter(|pace| {
   133→            if let Some(tack) = pace.tacks.first() {
   134→                tack.state != PaceState::Abandoned
   135→            } else {
   136→                true
   137→            }
   138→        }).count();
   139→
   140→        // Count paces where state == Complete
   141→        let completed_count = heat.paces.values().filter(|pace| {
   142→            if let Some(tack) = pace.tacks.first() {
   143→                tack.state == PaceState::Complete
   144→            } else {
   145→                false
   146→            }
   147→        }).count();
   148→
   149→        let status_str = match heat.status {
   150→            HeatStatus::Racing => "racing",
   151→            HeatStatus::Stabled => "stabled",
   152→            HeatStatus::Retired => "retired",
   153→        };
   154→
   155→        table.jjrp_print_row(&[
   156→            key,
   157→            &heat.silks,
   158→            status_str,
   159→            &completed_count.to_string(),
   160→            &defined_count.to_string(),
   161→        ]);
   162→    }
   163→
   164→    0
   165→}
