   669→// ============================================================================
   670→// Scout - Search across heats and paces with regex
   671→// ============================================================================
   672→
   673→/// Arguments for scout command
   674→#[derive(Debug)]
   675→pub struct jjrq_ScoutArgs {
   676→    pub file: std::path::PathBuf,
   677→    pub pattern: String,
   678→    pub actionable: bool,
   679→}
   680→
   681→/// Run the scout command - regex search across heats/paces
   682→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   683→    use regex::RegexBuilder;
   684→
   685→    let gallops = match Gallops::jjrg_load(&args.file) {
   686→        Ok(g) => g,
   687→        Err(e) => {
   688→            eprintln!("jjx_scout: error: {}", e);
   689→            return 1;
   690→        }
   691→    };
   692→
   693→    // Build case-insensitive regex
   694→    let re = match RegexBuilder::new(&args.pattern)
   695→        .case_insensitive(true)
   696→        .build()
   697→    {
   698→        Ok(r) => r,
   699→        Err(e) => {
   700→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   701→            return 1;
   702→        }
   703→    };
   704→
   705→    // Track which heats have matches (for group headers)
   706→    let mut current_heat_key: Option<String> = None;
   707→
   708→    // Iterate all heats (racing, stabled, retired)
   709→    for (heat_key, heat) in &gallops.heats {
   710→        // Search each pace in order
   711→        for coronet_key in &heat.order {
   712→            if let Some(pace) = heat.paces.get(coronet_key) {
   713→                if let Some(tack) = pace.tacks.first() {
   714→                    // Apply actionable filter if requested
   715→                    if args.actionable {
   716→                        match tack.state {
   717→                            PaceState::Rough | PaceState::Bridled => {},
   718→                            _ => continue,
   719→                        }
   720→                    }
   721→
   722→                    // Search: silks, spec (tack text), direction, paddock content
   723→                    // Use owned strings to avoid lifetime issues
   724→                    let mut match_result: Option<(String, String)> = None;
   725→
   726→                    if re.is_match(&tack.silks) {
   727→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   728→                    } else if re.is_match(&tack.text) {
   729→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   730→                    } else if let Some(ref direction) = tack.direction {
   731→                        if re.is_match(direction) {
   732→                            match_result = Some(("direction".to_string(), direction.clone()));
   733→                        }
   734→                    } else {
   735→                        // Search paddock content
   736→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   737→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   738→                            if re.is_match(&content) {
   739→                                match_result = Some(("paddock".to_string(), content));
   740→                            }
   741→                        }
   742→                    }
   743→
   744→                    // If we found a match, output it
   745→                    if let Some((field_name, field_content)) = match_result {
   746→                        // Print heat header if this is a new heat
   747→                        if current_heat_key.as_ref() != Some(heat_key) {
   748→                            println!("{} {}", heat_key, heat.silks);
   749→                            current_heat_key = Some(heat_key.clone());
   750→                        }
   751→
   752→                        // Print pace line
   753→                        let state_str = zjjrq_pace_state_str(&tack.state);
   754→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   755→
   756→                        // Print match line with context (extract ~60 chars around match)
   757→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   758→                        println!("    {}: {}", field_name, match_excerpt);
   759→                    }
   760→                }
   761→            }
   762→        }
   763→    }
   764→
   765→    0
   766→}
   767→
   768→/// Extract context around the first regex match in content
   769→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   770→    if let Some(mat) = re.find(content) {
   771→        let start = mat.start();
   772→        let end = mat.end();
   773→
   774→        // Find context window (30 chars before, 30 chars after)
   775→        let context_before = 30;
   776→        let context_after = 30;
   777→
   778→        let window_start = start.saturating_sub(context_before);
   779→        let window_end = (end + context_after).min(content.len());
   780→
   781→        let mut excerpt = String::new();
   782→        if window_start > 0 {
   783→            excerpt.push_str("...");
   784→        }
   785→        excerpt.push_str(&content[window_start..window_end]);
   786→        if window_end < content.len() {
   787→            excerpt.push_str("...");
   788→        }
   789→
   790→        // Replace newlines with spaces for single-line display
   791→        excerpt.replace('\n', " ").replace('\r', "")
   792→    } else {
   793→        // Shouldn't happen, but fallback to truncated content
   794→        let truncated = content.chars().take(60).collect::<String>();
   795→        if content.len() > 60 {
   796→            format!("{}...", truncated)
   797→        } else {
   798→            truncated
   799→        }
   800→    }
   801→}
