   949→/// Run the retire command - extract complete Heat data for archival
   950→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   951→    let gallops = match Gallops::jjrg_load(&args.file) {
   952→        Ok(g) => g,
   953→        Err(e) => {
   954→            eprintln!("jjx_retire: error: {}", e);
   955→            return 1;
   956→        }
   957→    };
   958→
   959→    let heat_key = args.firemark.jjrf_display();
   960→    let heat = match gallops.heats.get(&heat_key) {
   961→        Some(h) => h,
   962→        None => {
   963→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   964→            return 1;
   965→        }
   966→    };
   967→
   968→    // Read paddock file content
   969→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   970→        Ok(content) => content,
   971→        Err(e) => {
   972→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   973→            return 1;
   974→        }
   975→    };
   976→
   977→    // Build paces array with full tack history, ordered per Heat's order array
   978→    let mut paces = Vec::new();
   979→    for coronet_key in &heat.order {
   980→        if let Some(pace) = heat.paces.get(coronet_key) {
   981→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   982→                zjjrq_RetireTack {
   983→                    ts: tack.ts.clone(),
   984→                    state: match tack.state {
   985→                        PaceState::Rough => "rough".to_string(),
   986→                        PaceState::Bridled => "bridled".to_string(),
   987→                        PaceState::Complete => "complete".to_string(),
   988→                        PaceState::Abandoned => "abandoned".to_string(),
   989→                    },
   990→                    text: tack.text.clone(),
   991→                    direction: tack.direction.clone(),
   992→                }
   993→            }).collect();
   994→
   995→            paces.push(zjjrq_RetirePace {
   996→                coronet: coronet_key.clone(),
   997→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   998→                tacks,
   999→            });
  1000→        }
  1001→    }
  1002→
  1003→    let output = zjjrq_RetireOutput {
  1004→        firemark: heat_key.clone(),
  1005→        silks: heat.silks.clone(),
  1006→        created: heat.creation_time.clone(),
  1007→        status: match heat.status {
  1008→            HeatStatus::Racing => "racing".to_string(),
  1009→            HeatStatus::Stabled => "stabled".to_string(),
  1010→            HeatStatus::Retired => "retired".to_string(),
  1011→        },
  1012→        paddock_file: heat.paddock_file.clone(),
  1013→        paddock_content,
  1014→        paces,
  1015→        // TODO: Call jjx_rein internally to get steeplechase entries
  1016→    };
  1017→
  1018→    // Output JSON
  1019→    match serde_json::to_string_pretty(&output) {
  1020→        Ok(json) => {
  1021→            println!("{}", json);
  1022→            0
  1023→        }
  1024→        Err(e) => {
  1025→            eprintln!("jjx_retire: error serializing output: {}", e);
  1026→            1
  1027→        }
  1028→    }
  1029→}
