  1031→// ============================================================================
  1032→// Silks Sequence Parsing and Building
  1033→// ============================================================================
  1034→
  1035→/// Parse silks into (base, sequence_number)
  1036→///
  1037→/// Silks ending with a 2-digit sequence number are parsed into base and number.
  1038→/// Format: "foo-bar" -> ("foo-bar", None)
  1039→///         "foo-bar-01" -> ("foo-bar", Some(1))
  1040→///         "foo-bar-42" -> ("foo-bar", Some(42))
  1041→pub fn jjrq_parse_silks_sequence(silks: &str) -> (String, Option<u32>) {
  1042→    // Use regex ^(.+)-(\d{2})$ for suffix detection
  1043→    let re = match Regex::new(r"^(.+)-(\d{2})$") {
  1044→        Ok(r) => r,
  1045→        Err(_) => {
  1046→            // Fallback: return full silks as base, no sequence
  1047→            return (silks.to_string(), None);
  1048→        }
  1049→    };
  1050→
  1051→    if let Some(caps) = re.captures(silks) {
  1052→        if let (Some(base_match), Some(num_match)) = (caps.get(1), caps.get(2)) {
  1053→            let base = base_match.as_str().to_string();
  1054→            if let Ok(num_str) = num_match.as_str().parse::<u32>() {
  1055→                return (base, Some(num_str));
  1056→            }
  1057→        }
  1058→    }
  1059→
  1060→    // No match: return full silks as base, no sequence
  1061→    (silks.to_string(), None)
  1062→}
  1063→
  1064→/// Build garlanded silks: "garlanded-{base}-{seq:02}"
  1065→pub fn jjrq_build_garlanded_silks(base: &str, seq: u32) -> String {
  1066→    format!("garlanded-{}-{:02}", base, seq)
  1067→}
  1068→
  1069→/// Build continuation silks: "{base}-{seq:02}"
  1070→pub fn jjrq_build_continuation_silks(base: &str, seq: u32) -> String {
  1071→    format!("{}-{:02}", base, seq)
  1072→}
