  1075→mod tests {
  1076→    use super::*;
  1077→
  1078→    #[test]
  1079→    fn test_parse_silks_sequence_plain() {
  1080→        let (base, seq) = jjrq_parse_silks_sequence("foo-bar");
  1081→        assert_eq!(base, "foo-bar");
  1082→        assert_eq!(seq, None);
